@@ -0,0 +1,19 @@
+-- HD Wallet migration: replace per-account private keys with deterministic derivation indices.
+-- Pool account keys are now derived on-the-fly from a per-network HD mnemonic (env var).
+-- Existing pool accounts with random keys are dropped — fresh HD-derived accounts will be created on startup.
+
+BEGIN;
+
+-- Remove all existing pool accounts (they used randomly generated keys)
+DELETE FROM deposit_pool_account_locks;
+DELETE FROM deposit_pool_account;
+
+-- Drop the private_key column, add derivation_index
+ALTER TABLE deposit_pool_account DROP COLUMN private_key;
+ALTER TABLE deposit_pool_account ADD COLUMN derivation_index INTEGER NOT NULL;
+
+-- Ensure no two accounts on the same network share a derivation index
+CREATE UNIQUE INDEX idx_deposit_pool_account_network_derivation
+  ON deposit_pool_account (network, derivation_index);
+
+COMMIT;
