    27→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    28→    private readonly hdWalletService: HdWalletService,
    29→    private readonly outstandingTronAccountService: OutstandingTronAccountService,
    30→    @Inject(networksConfigs.KEY)
    31→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    32→  ) {}
    33→
    34→  async onModuleInit(): Promise<void> {
    35→    await Promise.all([
    36→      this.adjustPoolCount(SupportedNetworks.TRON),
    37→      this.adjustPoolCount(SupportedNetworks.ETHEREUM),
    38→      this.adjustPoolCount(SupportedNetworks.BNB),
    39→    ]);
    40→  }
    41→
    42→  async adjustPoolCount(
    43→    network: SupportedNetworks,
    44→    targetCount: number = 2,
    45→  ): Promise<void> {
    46→    const trx = await this.db.startTransaction().execute();
    47→
    48→    try {
    49→      const existingPoolCount = await trx
    50→        .selectFrom('depositPoolAccount')
    51→        .select(({ fn }) => [fn.count<number>('id').as('count')])
    52→        .where('network', '=', network)
    53→        .executeTakeFirst();
    54→
    55→      const countToCreate = targetCount - (existingPoolCount.count ?? 0);
    56→      if (countToCreate <= 0) {
    57→        this.logger.log({
    58→          message: 'Pool already has enough accounts',
    59→          network,
    60→          targetCount,
    61→          existingPoolCount: existingPoolCount.count,
    62→        });
    63→        await trx.rollback().execute();
    64→        return;
    65→      }
    66→
    67→      const maxIndexResult = await trx
    68→        .selectFrom('depositPoolAccount')
    69→        .select(({ fn }) => [fn.max<number>('derivationIndex').as('maxIndex')])
    70→        .where('network', '=', network)
    71→        .executeTakeFirst();
    72→
    73→      let nextIndex = (maxIndexResult?.maxIndex ?? -1) + 1;
    74→
    75→      const poolAccounts = [];
    76→      const addresses: string[] = [];
    77→      for (let i = 0; i < countToCreate; i++) {
    78→        const derived = this.hdWalletService.deriveWallet(network, nextIndex);
    79→
    80→        const poolAccount = await trx
    81→          .insertInto('depositPoolAccount')
    82→          .values({
    83→            address: derived.address,
    84→            derivationIndex: nextIndex,
    85→            network: network,
    86→          })
    87→          .returningAll()
    88→          .executeTakeFirstOrThrow();
    89→
    90→        poolAccounts.push(poolAccount);
    91→        addresses.push(derived.address);
    92→        nextIndex++;
    93→      }
    94→
    95→      if (network === SupportedNetworks.TRON) {
    96→        await this.outstandingTronAccountService.activateAccounts(addresses);
    97→      }
    98→
    99→      await trx.commit().execute();
   100→
   101→      this.logger.log({
   102→        message: 'Pool created',
   103→        network,
   104→        accountCount: poolAccounts.length,
   105→      });
   106→    } catch (error) {
   107→      await trx.rollback().execute();
   108→      this.logger.error({ error, message: 'Failed to create pool', network });
   109→      throw error;
   110→    }
   111→  }
   112→
   113→  /**
   114→   * Gets an available pool account row (FOR UPDATE) within an existing transaction.
   115→   * This is used when the caller (e.g. DepositService) manages the full transaction lifecycle.
   116→   * Returns an account that is not locked for the given currency.
   117→   */
   118→  async getAndLockAvailablePoolAccount(
   119→    trx: ControlledTransaction<Database, []>,
   120→    options: {
   121→      network: SupportedNetworks;
   122→      currencyCode: string;
   123→    },
   124→  ): Promise<{ id: UUID; address: string } | undefined> {
   125→    const allPoolAccounts = await trx
   126→      .selectFrom('depositPoolAccount')
   127→      .forUpdate()
   128→      .select(['id', 'address'])
   129→      .where('network', '=', options.network)
   130→      .execute();
   131→
   132→    const lockedPoolAccountIds = await trx
   133→      .selectFrom('depositPoolAccountLocks')
   134→      .select(['depositPoolAccountId'])
   135→      .where('currencyCode', '=', options.currencyCode)
   136→      .execute();
   137→
   138→    const lockedIdsSet = new Set(
   139→      lockedPoolAccountIds.map((lock) => lock.depositPoolAccountId),
   140→    );
   141→
   142→    // Find the first available account that is not locked for this currency
   143→    const availableAccount = allPoolAccounts.find(
   144→      (account) => !lockedIdsSet.has(account.id),
   145→    );
   146→
   147→    if (!availableAccount) {
   148→      throw ExceptionFactory.create({
   149→        exceptionCode: 'deposit.noAvailablePoolAccount',
   150→        statusCode: HttpStatus.BAD_REQUEST,
   151→        message: `No available pool account found for ${options.network} network. All accounts may be in use.`,
   152→      });
   153→    }
   154→
   155→    await this.lockPoolAccount(availableAccount.id, options.currencyCode, trx);
   156→
   157→    return { id: availableAccount.id, address: availableAccount.address };
   158→  }
   159→
   160→  async setDepositIdOnLockRecord(
   161→    depositId: UUID,
   162→    poolAccountId: UUID,
   163→    currencyCode: string,
   164→    trx: ControlledTransaction<Database, []>,
   165→  ): Promise<void> {
   166→    await trx
   167→      .updateTable('depositPoolAccountLocks')
   168→      .set({
   169→        depositId: depositId,
   170→      })
   171→      .where('depositPoolAccountId', '=', poolAccountId)
   172→      .where('currencyCode', '=', currencyCode)
   173→      .execute();
   174→  }
   175→
   176→  /**
   177→   * Locks a pool account to a specific currency and deposit
   178→   * This is used when the account has already been selected via getAvailablePoolAccountForUpdate
   179→   */
   180→  async lockPoolAccount(
   181→    poolAccountId: UUID,
   182→    currencyCode: string,
   183→    trx: ControlledTransaction<Database, []>,
   184→  ): Promise<void> {
   185→    const existingLock = await trx
   186→      .selectFrom('depositPoolAccountLocks')
   187→      .selectAll()
   188→      .where('depositPoolAccountId', '=', poolAccountId)
   189→      .where('currencyCode', '=', currencyCode)
   190→      .executeTakeFirst();
   191→    if (existingLock) {
   192→      throw ExceptionFactory.create({
   193→        exceptionCode: 'deposit.poolAccountAlreadyLocked',
   194→        statusCode: HttpStatus.BAD_REQUEST,
   195→        message: `Pool account ${poolAccountId} already locked`,
   196→      });
   197→    }
   198→
   199→    await trx
   200→      .insertInto('depositPoolAccountLocks')
   201→      .values({
   202→        depositPoolAccountId: poolAccountId,
   203→        currencyCode: currencyCode,
   204→      })
   205→      .execute();
   206→
   207→    this.logger.log({
   208→      message: 'Pool account locked',
   209→      poolAccountId,
   210→      currencyCode,
   211→    });
   212→  }
   213→
   214→  /**
   215→   * Unlocks a pool account after deposit finished
   216→   */
   217→  async unlockPoolAccount(
   218→    poolAccountId: UUID,
   219→    currencyCode: string,
   220→    _trx?: ControlledTransaction<Database, []>,
   221→  ): Promise<void> {
   222→    const trx = _trx ?? (await this.db.startTransaction().execute());
   223→    await trx
   224→      .deleteFrom('depositPoolAccountLocks')
   225→      .where('depositPoolAccountId', '=', poolAccountId)
   226→      .where('currencyCode', '=', currencyCode)
   227→      .execute();
   228→
   229→    this.logger.log({ message: 'Pool account unlocked', poolAccountId });
   230→    if (!_trx) {
   231→      await trx.commit().execute();
   232→    }
   233→  }
   234→
   235→  async getAccountById(
   236→    poolAccountId: UUID,
   237→  ): Promise<Selectable<DepositPoolAccountEntity>> {
   238→    const result = await this.db
   239→      .selectFrom('depositPoolAccount')
   240→      .selectAll()
   241→      .where('id', '=', poolAccountId)
   242→      .executeTakeFirstOrThrow();
   243→
   244→    return result;
   245→  }
   246→}
