     1→import { Inject, Injectable, Logger, OnModuleInit } from '@nestjs/common';
     2→import { ConfigType } from '@nestjs/config';
     3→import { ethers } from 'ethers';
     4→import { TronWeb } from 'tronweb';
     5→import { networksConfigs } from '@configs/networks.configs';
     6→import { SupportedNetworks } from '../types/network.type';
     7→
     8→export interface DerivedWallet {
     9→  address: string;
    10→  privateKey: string;
    11→}
    12→
    13→const BIP44_COIN_TYPES: Record<string, number> = {
    14→  [SupportedNetworks.ETHEREUM]: 60,
    15→  [SupportedNetworks.BNB]: 60,
    16→  [SupportedNetworks.TRON]: 195,
    17→};
    18→
    19→const HD_SUPPORTED_NETWORKS = [
    20→  SupportedNetworks.TRON,
    21→  SupportedNetworks.ETHEREUM,
    22→  SupportedNetworks.BNB,
    23→] as const;
    24→
    25→@Injectable()
    26→export class HdWalletService implements OnModuleInit {
    27→  private readonly logger = new Logger(HdWalletService.name);
    28→
    29→  /**
    30→   * Cached account-level HD nodes per network.
    31→   * Parsed once on init to avoid re-running PBKDF2 (2048 rounds) on every derivation.
    32→   * Each node sits at m/44'/coinType'/0'/0 — child derivation from here is a fast
    33→   * single HMAC-SHA512 operation.
    34→   */
    35→  private readonly accountNodes = new Map<
    36→    SupportedNetworks,
    37→    ethers.HDNodeWallet
    38→  >();
    39→
    40→  constructor(
    41→    @Inject(networksConfigs.KEY)
    42→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    43→  ) {}
    44→
    45→  onModuleInit(): void {
    46→    for (const network of HD_SUPPORTED_NETWORKS) {
    47→      const phrase = this.getMnemonicPhrase(network);
    48→
    49→      let mnemonic: ethers.Mnemonic;
    50→      try {
    51→        mnemonic = ethers.Mnemonic.fromPhrase(phrase);
    52→      } catch {
    53→        throw new Error(
    54→          `Invalid BIP-39 mnemonic for ${network}. Check the corresponding HD_MNEMONIC env var.`,
    55→        );
    56→      }
    57→
    58→      const coinType = BIP44_COIN_TYPES[network];
    59→      const accountPath = `m/44'/${coinType}'/0'/0`;
    60→      const accountNode = ethers.HDNodeWallet.fromMnemonic(
    61→        mnemonic,
    62→        accountPath,
    63→      );
    64→
    65→      this.accountNodes.set(network, accountNode);
    66→      this.logger.log({ message: `HD account node initialised`, network });
    67→    }
    68→  }
    69→
    70→  deriveWallet(network: SupportedNetworks, index: number): DerivedWallet {
    71→    const child = this.deriveChild(network, index);
    72→
    73→    if (network === SupportedNetworks.TRON) {
    74→      const rawKey = child.privateKey.slice(2);
    75→      const address = TronWeb.address.fromPrivateKey(rawKey) as string;
    76→      return { address, privateKey: rawKey };
    77→    }
    78→
    79→    return { address: child.address, privateKey: child.privateKey };
    80→  }
    81→
    82→  deriveAddress(network: SupportedNetworks, index: number): string {
    83→    return this.deriveWallet(network, index).address;
    84→  }
    85→
    86→  /**
    87→   * Derives the private key and verifies it matches the expected address.
    88→   * Throws if there is a mismatch (mnemonic changed, DB corruption, etc.).
    89→   */
    90→  deriveAndVerify(
    91→    network: SupportedNetworks,
    92→    index: number,
    93→    expectedAddress: string,
    94→  ): DerivedWallet {
    95→    const wallet = this.deriveWallet(network, index);
    96→    if (wallet.address !== expectedAddress) {
    97→      throw new Error(
    98→        `HD derivation mismatch for ${network} index ${index}: ` +
    99→          `expected ${expectedAddress}, got ${wallet.address}. ` +
   100→          `The mnemonic may have been changed or the DB record is corrupt.`,
   101→      );
   102→    }
   103→    return wallet;
   104→  }
   105→
   106→  private deriveChild(
   107→    network: SupportedNetworks,
   108→    index: number,
   109→  ): ethers.HDNodeWallet {
   110→    const accountNode = this.accountNodes.get(network);
   111→    if (!accountNode) {
   112→      throw new Error(`HD wallet not initialised for network: ${network}`);
   113→    }
   114→    return accountNode.deriveChild(index);
   115→  }
   116→
   117→  private getMnemonicPhrase(network: SupportedNetworks): string {
   118→    switch (network) {
   119→      case SupportedNetworks.TRON:
   120→        return this.networksConfig.tron.hdMnemonic;
   121→      case SupportedNetworks.ETHEREUM:
   122→        return this.networksConfig.ethereum.hdMnemonic;
   123→      case SupportedNetworks.BNB:
   124→        return this.networksConfig.bnb.hdMnemonic;
   125→      default:
   126→        throw new Error(`HD wallet not supported for network: ${network}`);
   127→    }
   128→  }
   129→}
