    48→  async getTokenBalance(
    49→    address: string,
    50→    currencyCode: string,
    51→  ): Promise<string> {
    52→    const currency = await this.currencyService.getCurrencyByCode(currencyCode);
    53→
    54→    if (!currency || !currency.contractAddress) {
    55→      throw new Error(
    56→        `Currency ${currencyCode} not found or missing contract address`,
    57→      );
    58→    }
    59→
    60→    // Use standard TRC-20 ABI instead of fetching from chain
    61→    const contract = this.tronWeb.contract(
    62→      TRC20_ABI.entrys,
    63→      currency.contractAddress,
    64→    );
    65→
    66→    // For balanceOf, we need to specify the 'from' address (any address can call this view function)
    67→    // Using the same address being queried as the caller
    68→    const balance = await contract.methods
    69→      .balanceOf(address)
    70→      .call({ from: address });
    71→
    72→    return new Decimal(balance).div(10 ** currency.decimalPlaces).toString();
    73→  }
