import { HttpStatus, Inject, Injectable, Logger } from '@nestjs/common';
import { ExceptionFactory } from '@shared/exceptions';
import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
import { Db } from '@shared/database/types';
import { UUID } from 'crypto';
import { SupportedNetworks } from '@modules/networks/types/network.type';

import { NetworksService } from '@modules/networks/services/networks.service';
import { OutstandingTronAccountService } from '@modules/networks/tron/services/outstanding-tron.account';
import { ControlledTransaction, Selectable } from 'kysely';
import { Database } from '../../../db/database.type';
import { DepositPoolAccountEntity } from '@entities/balance.entity';
import { networksConfigs } from '@configs/networks.configs';
import { ConfigType } from '@nestjs/config';

@Injectable()
export class DepositPoolService {
  private readonly logger = new Logger(DepositPoolService.name);

  constructor(
    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    private readonly networksService: NetworksService,
    private readonly outstandingTronAccountService: OutstandingTronAccountService,
    @Inject(networksConfigs.KEY)
    private readonly networksConfig: ConfigType<typeof networksConfigs>,
  ) {
    //this.adjustPoolCount(SupportedNetworks.TRON);
    //this.adjustPoolCount(SupportedNetworks.ETHEREUM);
  }

  /**
   * Creates a global pool of 3 accounts for a network
   * Accounts are activated using the outstanding account service
   */
  async adjustPoolCount(
    network: SupportedNetworks,
    targetCount: number = 2,
  ): Promise<void> {
    const trx = await this.db.startTransaction().execute();

    try {
      // Check if pool already exists
      const existingPoolCount = await trx
        .selectFrom('depositPoolAccount')
        .select(({ fn }) => [fn.count<number>('id').as('count')])
        .where('network', '=', network)
        .executeTakeFirst();

      const countToCreate = targetCount - (existingPoolCount.count ?? 0);
      if (countToCreate <= 0) {
        this.logger.log({
          message: 'Pool already has enough accounts',
          network,
          targetCount,
          existingPoolCount: existingPoolCount.count,
        });
        return;
      }

      // Create 3 pool accounts
      const poolAccounts = [];
      const addresses: string[] = [];
      for (let i = 0; i < countToCreate; i++) {
        const networkAccount =
          await this.networksService.createAccount(network);

        // Create pool account record with address and privateKey directly
        const poolAccount = await trx
          .insertInto('depositPoolAccount')
          .values({
            address: networkAccount.address,
            privateKey: networkAccount.privateKey,
            network: network,
          })
          .returningAll()
          .executeTakeFirstOrThrow();

        poolAccounts.push(poolAccount);
        addresses.push(networkAccount.address);
      }

      // Activate accounts using outstanding account service (for Tron)
      if (network === SupportedNetworks.TRON) {
        await this.outstandingTronAccountService.activateAccounts(addresses);
      }

      await trx.commit().execute();

      this.logger.log({
        message: 'Pool created',
        network,
        accountCount: poolAccounts.length,
      });
    } catch (error) {
      await trx.rollback().execute();
      this.logger.error({ error, message: 'Failed to create pool', network });
      throw error;
    }
  }

  /**
   * Gets an available pool account row (FOR UPDATE) within an existing transaction.
   * This is used when the caller (e.g. DepositService) manages the full transaction lifecycle.
   * Returns an account that is not locked for the given currency.
   */
  async getAndLockAvailablePoolAccount(
    trx: ControlledTransaction<Database, []>,
    options: {
      network: SupportedNetworks;
      currencyCode: string;
    },
  ): Promise<{ id: UUID; address: string } | undefined> {
    const allPoolAccounts = await trx
      .selectFrom('depositPoolAccount')
      .forUpdate()
      .select(['id', 'address'])
      .where('network', '=', options.network)
      .execute();

    const lockedPoolAccountIds = await trx
      .selectFrom('depositPoolAccountLocks')
      .select(['depositPoolAccountId'])
      .where('currencyCode', '=', options.currencyCode)
      .execute();

    const lockedIdsSet = new Set(
      lockedPoolAccountIds.map((lock) => lock.depositPoolAccountId),
    );

    // Find the first available account that is not locked for this currency
    const availableAccount = allPoolAccounts.find(
      (account) => !lockedIdsSet.has(account.id),
    );

    if (!availableAccount) {
      throw ExceptionFactory.create({
        exceptionCode: 'deposit.noAvailablePoolAccount',
        statusCode: HttpStatus.BAD_REQUEST,
        message: `No available pool account found for ${options.network} network. All accounts may be in use.`,
      });
    }

    await this.lockPoolAccount(availableAccount.id, options.currencyCode, trx);

    return { id: availableAccount.id, address: availableAccount.address };
  }

  async setDepositIdOnLockRecord(
    depositId: UUID,
    poolAccountId: UUID,
    currencyCode: string,
    trx: ControlledTransaction<Database, []>,
  ): Promise<void> {
    await trx
      .updateTable('depositPoolAccountLocks')
      .set({
        depositId: depositId,
      })
      .where('depositPoolAccountId', '=', poolAccountId)
      .where('currencyCode', '=', currencyCode)
      .execute();
  }

  /**
   * Locks a pool account to a specific currency and deposit
   * This is used when the account has already been selected via getAvailablePoolAccountForUpdate
   */
  async lockPoolAccount(
    poolAccountId: UUID,
    currencyCode: string,
    trx: ControlledTransaction<Database, []>,
  ): Promise<void> {
    const existingLock = await trx
      .selectFrom('depositPoolAccountLocks')
      .selectAll()
      .where('depositPoolAccountId', '=', poolAccountId)
      .where('currencyCode', '=', currencyCode)
      .executeTakeFirst();
    if (existingLock) {
      throw ExceptionFactory.create({
        exceptionCode: 'deposit.poolAccountAlreadyLocked',
        statusCode: HttpStatus.BAD_REQUEST,
        message: `Pool account ${poolAccountId} already locked`,
      });
    }

    await trx
      .insertInto('depositPoolAccountLocks')
      .values({
        depositPoolAccountId: poolAccountId,
        currencyCode: currencyCode,
      })
      .execute();

    this.logger.log({
      message: 'Pool account locked',
      poolAccountId,
      currencyCode,
    });
  }

  /**
   * Unlocks a pool account after deposit finished
   */
  async unlockPoolAccount(
    poolAccountId: UUID,
    currencyCode: string,
    _trx?: ControlledTransaction<Database, []>,
  ): Promise<void> {
    const trx = _trx ?? (await this.db.startTransaction().execute());
    await trx
      .deleteFrom('depositPoolAccountLocks')
      .where('depositPoolAccountId', '=', poolAccountId)
      .where('currencyCode', '=', currencyCode)
      .execute();

    this.logger.log({ message: 'Pool account unlocked', poolAccountId });
    if (!_trx) {
      await trx.commit().execute();
    }
  }

  /**
   * Gets pool account by ID with address and private key
   */
  async getAccountById(
    poolAccountId: UUID,
  ): Promise<Selectable<DepositPoolAccountEntity>> {
    const result = await this.db
      .selectFrom('depositPoolAccount')
      .selectAll()
      .where('id', '=', poolAccountId)
      .executeTakeFirstOrThrow();

    return result;
  }
}

import { Inject, Injectable, Logger } from '@nestjs/common';
import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
import { Db } from '@shared/database/types';
import { NetworksService } from '@modules/networks/services/networks.service';
import { CurrencyService } from '@modules/currency/services/currency.service';
import { networksConfigs } from '@configs/networks.configs';
import { ConfigType } from '@nestjs/config';
import { SupportedNetworks } from '@modules/networks/types/network.type';
import { Selectable } from 'kysely';
import { DepositPoolAccountEntity } from '@entities/balance.entity';
import { CurrencyEntity } from '@entities/currency.entity';
import Decimal from 'decimal.js';

@Injectable()
export class DepositPoolMonitoringService {
  constructor(
    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    private readonly networksService: NetworksService,
    private readonly currencyService: CurrencyService,
    @Inject(networksConfigs.KEY)
    private readonly networksConfig: ConfigType<typeof networksConfigs>,
  ) {
    //this.monitorPoolAccounts(SupportedNetworks.TRON);
  }
  private readonly logger = new Logger(DepositPoolMonitoringService.name);

  /**
   * Monitors pool accounts and sweeps funds if balance exceeds threshold
   * Sweeps funds keeping min_deposit_pool_account_amount in the pool account
   */
  async monitorPoolAccounts(network: SupportedNetworks): Promise<void> {
    const trx = await this.db.startTransaction().execute();
    try {
      // Get all pool accounts for
      const poolAccounts = await trx
        .selectFrom('depositPoolAccount')
        // for update to prevent concurrent access
        .forUpdate()
        .selectAll()
        .where('network', '=', network)
        .where((eb) =>
          eb.or([
            eb('lastMonitorAt', 'is', null),
            eb('lastMonitorAt', '<', new Date(Date.now() - 15 * 60 * 1000)), // Only check accounts that have not been monitored yet or lastMonitorAt was more then 15 minutes ago
          ]),
        )
        .where((eb) =>
          eb(
            'id',
            'not in',
            eb
              .selectFrom('depositPoolAccountLocks')
              .select('depositPoolAccountId'),
          ),
        )
        .execute();

      if (poolAccounts.length === 0) {
        this.logger.log({ message: 'No pool accounts to monitor', network });
        await trx.rollback().execute();
        return;
      }

      this.logger.log({
        message: `Found ${poolAccounts.length} pool accounts to monitor in ${network} network`,
        network,
      });

      const outstandingAccount =
        await this.networksService.getOutstandingAccountByNetwork(network);

      if (!outstandingAccount) {
        this.logger.warn({ message: 'Outstanding account not found', network });
        await trx.rollback().execute();
        return;
      }

      const networkCurrencies = await this.currencyService.getCurrencies({
        network,
      });

      // Find base currency that matches the network
      const baseCurrency = networkCurrencies.find(
        (c) => !c.contractAddress && c.network === network,
      );

      // Process each pool account
      for (const poolAccount of poolAccounts) {
        // Get currency information (lockedCurrencyId is guaranteed to be set since we filtered for it)

        if (!baseCurrency) {
          this.logger.warn({ message: 'Base currency not found', network });
          continue;
        }

        await this.sweepBalanceIfRequired(
          poolAccount,
          networkCurrencies,
          outstandingAccount,
        ).catch((error) => {
          this.logger.error({
            error,
            message: 'Failed to sweep balance if required',
            poolAccountId: poolAccount.id,
            network,
          });
        });
        await this.topUpIfNeeded(
          poolAccount,
          baseCurrency,
          outstandingAccount,
        ).catch((error) => {
          this.logger.error({
            error,
            message: 'Failed to top up if needed',
            poolAccountId: poolAccount.id,
            network,
          });
        });

        await trx
          .updateTable('depositPoolAccount')
          .set({
            lastMonitorAt: new Date(),
          })
          .where('id', '=', poolAccount.id)
          .execute();
      }

      await trx.commit().execute();
    } catch (error) {
      await trx.rollback().execute();
      this.logger.error({
        error,
        message: 'Failed to monitor and sweep pool accounts',
        network,
      });
      throw error;
    }
  }

  private async sweepBalanceIfRequired(
    poolAccount: Selectable<DepositPoolAccountEntity>,
    networkCurrencies: Selectable<CurrencyEntity>[],
    outstandingAccount: { address: string; privateKey: string },
  ): Promise<void> {
    //const threshold = new Decimal(currency.thresholdPoolAccountBalanceToSweep);

    for (const currency of networkCurrencies) {
      const balance = await this.networksService.getBalanceByAddress(
        poolAccount.network,
        poolAccount.address,
        currency.contractAddress,
      );
      if (
        balance.found &&
        new Decimal(balance.amount).gt(
          currency.thresholdPoolAccountBalanceToSweep,
        )
      ) {
        const optimalAmount = new Decimal(currency.optimalPoolAccountBalance);
        const sweepAmount = optimalAmount.minus(balance.amount).abs();

        const date = new Date();
        const idempotencyKey = `monitoring-sweep-${poolAccount.id}-${currency.code}-${date.getUTCFullYear()}-${date.getUTCMonth()}-${date.getUTCDate()}-${date.getUTCHours()}-${date.getUTCMinutes()}}`;

        await this.networksService.sweepFunds(
          poolAccount.network,
          currency.code,
          {
            fromPrivateKey: poolAccount.privateKey,
            fromAddress: poolAccount.address,
            toAddress: outstandingAccount.address,
            amount: sweepAmount.toString(),
            idempotencyKey,
          },
        );
      }
    }
  }

  // Use only for base currency
  async topUpIfNeeded(
    poolAccount: Selectable<DepositPoolAccountEntity>,
    currency: Selectable<CurrencyEntity>,
    outstandingAccount: { address: string; privateKey: string },
  ): Promise<void> {
    const balance = await this.networksService.getBalanceByAddress(
      poolAccount.network,
      poolAccount.address,
      null,
    );
    const balanceDecimal = new Decimal(balance.amount);
    if (balanceDecimal.lt(currency.minPoolAccountBalance)) {
      // min = 50, optimal = 250, threshold = 500
      // topup amount = optimal - 40 - min
      const topupAmount = new Decimal(currency.optimalPoolAccountBalance).minus(
        balanceDecimal,
      );
      //console.log('topupAmount', topupAmount.toString());
      const date = new Date();
      const idempotencyKey = `monitoring-topup-${poolAccount.id}-${currency.code}-${date.getUTCFullYear()}-${date.getUTCMonth()}-${date.getUTCDate()}-${date.getUTCHours()}-${date.getUTCMinutes()}}`;
      console.log({ poolAccount, currency, topupAmount });
      await this.networksService.sweepFunds(
        poolAccount.network,
        currency.code,
        {
          fromAddress: outstandingAccount.address,
          fromPrivateKey: outstandingAccount.privateKey,
          toAddress: poolAccount.address,
          amount: topupAmount.toString(),
          idempotencyKey,
        },
      );
    }
  }
}

import { Inject, Injectable } from '@nestjs/common';
import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
import { Db } from '@shared/database/types';
import { TronWeb } from 'tronweb';
import { CurrencyService } from '@modules/currency/services/currency.service';
import { Decimal } from 'decimal.js';
import { INetworkAccount } from '../../types/network-account.type';
import { INetworkService, ISweepBaseParams } from '../../types/network-service';
import { SupportedNetworks } from '../../types/network.type';
import { TRC20_ABI } from '../constant';
import { networksConfigs } from '@configs/networks.configs';
import { ConfigType } from '@nestjs/config';
import { TronGridService } from './tron-grid.service';
import {
  IGetTransactionHistoryParams,
  INetworkTransaction,
} from '@modules/networks/types/network.type';

@Injectable()
export class TronNetworkService implements INetworkService {
  constructor(
    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    private readonly currencyService: CurrencyService,
    @Inject(networksConfigs.KEY)
    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    private readonly tronGridService: TronGridService,
  ) {
    this.tronWeb = new TronWeb({
      fullHost: this.networksConfig.tron.url,
    });
  }

  private readonly tronWeb: TronWeb;

  readonly networkName: SupportedNetworks.TRON = SupportedNetworks.TRON;

  async createAccount(): Promise<INetworkAccount> {
    const account = await this.tronWeb.createAccount();

    return {
      address: account.address.base58,
      privateKey: account.privateKey,
      publicKey: account.publicKey,
      meta: JSON.parse(JSON.stringify(account)),
    };
  }

  async getTokenBalance(
    address: string,
    currencyCode: string,
  ): Promise<string> {
    const currency = await this.currencyService.getCurrencyByCode(currencyCode);

    if (!currency || !currency.contractAddress) {
      throw new Error(
        `Currency ${currencyCode} not found or missing contract address`,
      );
    }

    // Use standard TRC-20 ABI instead of fetching from chain
    const contract = this.tronWeb.contract(
      TRC20_ABI.entrys,
      currency.contractAddress,
    );

    // For balanceOf, we need to specify the 'from' address (any address can call this view function)
    // Using the same address being queried as the caller
    const balance = await contract.methods
      .balanceOf(address)
      .call({ from: address });

    return new Decimal(balance).div(10 ** currency.decimalPlaces).toString();
  }

  async getTronBalance(address: string): Promise<number> {
    const balance = await this.tronWeb.trx.getBalance(address);
    return balance;
  }

  async getTrxBalance(address: string): Promise<string> {
    const balance = new Decimal(await this.tronWeb.trx.getBalance(address));
    return balance
      .div(10 ** 6)
      .toDecimalPlaces(6)
      .toString();
  }

  async geTtrxBalanceByPrivateKey(privateKey: string): Promise<string> {
    const wallet = this.tronWeb.address.fromPrivateKey(privateKey);
    return this.getTrxBalance(wallet as string);
  }

  /**
   * Sweeps TRC-20 tokens from a one-time wallet to a destination address
   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
   * @param currencyCode Currency code (e.g., 'USDT')
   * @param destinationAddress Address to sweep tokens to
   * @returns Transaction hash
   */
  async sweepToken(
    oneTimeWalletPrivateKey: string,
    currencyCode: string,
    destinationAddress: string,
    amount?: string,
  ): Promise<{ transactionHash: string; amount: string }> {
    try {
      const currency =
        await this.currencyService.getCurrencyByCode(currencyCode);

      if (!currency || !currency.contractAddress) {
        throw new Error(
          `Currency ${currencyCode} not found or missing contract address`,
        );
      }

      const contractAddress = currency.contractAddress;

      // Create wallet from private key
      const wallet = this.tronWeb.address.fromPrivateKey(
        oneTimeWalletPrivateKey,
      );

      // Create contract instance using standard TRC-20 ABI to get balance
      const contract = this.tronWeb.contract(TRC20_ABI.entrys, contractAddress);

      // Get balance of the one-time wallet
      const balance = await contract.methods
        .balanceOf(wallet)
        .call({ from: wallet });

      if (balance.toString() === '0') {
        throw new Error('No tokens to sweep');
      }

      const rawAmount = amount
        ? new Decimal(amount).mul(10 ** currency.decimalPlaces).toFixed(0)
        : balance.toString();

      if (new Decimal(rawAmount).gt(balance.toString())) {
        throw new Error(
          `Insufficient token balance: requested ${rawAmount}, available ${balance.toString()}`,
        );
      }

      // Use triggerSmartContract as per TronWeb documentation
      // https://tronweb.network/docu/docs/Transfer%20Token/
      const functionSelector = 'transfer(address,uint256)';
      const parameter = [
        { type: 'address', value: destinationAddress },
        { type: 'uint256', value: rawAmount },
      ];

      // Set feeLimit for TRC-20 transfers (consumes energy)
      const feeLimit = 18_000_000; // 18 TRX in SUN

      // Build the transaction using triggerSmartContract
      const tx = await this.tronWeb.transactionBuilder.triggerSmartContract(
        contractAddress,
        functionSelector,
        { feeLimit }, // Options object with feeLimit
        parameter,
        wallet as string, // issuerAddress - the address that will sign and send the transaction
      );

      // Sign the transaction with the private key
      const signedTx = await this.tronWeb.trx.sign(
        tx.transaction,
        oneTimeWalletPrivateKey,
      );

      // Send the signed transaction
      const result = await this.tronWeb.trx.sendRawTransaction(signedTx);

      // Extract transaction hash from result
      if (result.result) {
        const txHash = result.txid || tx.transaction?.txID || '';
        const sentAmount = new Decimal(rawAmount)
          .div(10 ** currency.decimalPlaces)
          .toString();
        return { transactionHash: txHash, amount: sentAmount };
      } else {
        throw new Error(
          `Transaction failed: ${result.message || 'Unknown error'}`,
        );
      }
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : String(error);
      throw new Error(`Failed to sweep token: ${errorMessage}`);
    }
  }

  /**
   * Sweeps TRX from a one-time wallet to a destination address
   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
   * @param destinationAddress Address to sweep TRX to
   * @returns Transaction hash
   */
  async sweepBase(
    params: ISweepBaseParams,
  ): Promise<{ transactionHash: string; amount: string }> {
    try {
      // Create wallet from private key
      const wallet = this.tronWeb.address.fromPrivateKey(params.fromPrivateKey);

      // Get balance (in SUN, 1 TRX = 1,000,000 SUN)
      const balance = await this.tronWeb.trx.getBalance(wallet);

      if (balance === 0) {
        throw new Error('No TRX to sweep');
      }

      //const sendAmount = new Decimal(params.amount).mul(1_000_000).toNumber();

      // Calculate amount to send (subtract transaction fee)
      // Current TRX transfer fee is ~1.1 TRX
      // Using 1,200,000 SUN (1.2 TRX) as a safe buffer for fees
      const fee = 1_200_000; // 1.2 TRX in SUN (safe buffer, actual fee ~1.1 TRX)
      const availableBalance = new Decimal(balance)
        .minus(fee)
        .minus(params.amount ?? 0)
        .toNumber();
      //.minus(sendAmount).toNumber());

      if (availableBalance <= 0) {
        throw new Error('Insufficient balance after fee deduction');
      }

      let sendAmount = params.amount
        ? new Decimal(params.amount).mul(1_000_000)
        : new Decimal(availableBalance);

      // Transfer TRX to destination
      // According to TronWeb docs, use sendTrx() for TRX transfers
      // sendTrx() handles transaction creation, signing, and broadcasting automatically
      const tx = await this.tronWeb.trx.sendTrx(
        params.toAddress,
        parseFloat(sendAmount.toString()),
        {
          privateKey: params.fromPrivateKey,
        },
      );

      return {
        transactionHash: tx.txid,
        amount: sendAmount.div(1_000_000).toString(),
      };
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : String(error);
      throw new Error(`Failed to sweep TRX: ${errorMessage}`);
    }
  }

  async verifyTransaction(transactionHash: string): Promise<boolean> {
    try {
      const info = await this.tronWeb.trx.getTransactionInfo(transactionHash);
      return info && typeof info.id === 'string' && info.id.length > 0;
    } catch {
      return false;
    }
  }

  /**
   * Gets transaction history for an address using TronGrid API
   * Delegates to TronGridService
   * @param address The address to get transaction history for
   * @param contractAddress Optional contract address for TRC20 token transactions (null for TRX transactions)
   * @param sinceTimestamp Optional timestamp to filter transactions after this time (in milliseconds)
   * @returns Array of incoming transactions
   */
  async getTransactionHistory(
    options: IGetTransactionHistoryParams,
  ): Promise<INetworkTransaction[]> {
    return this.tronGridService.getTransactionHistory(options);
  }
}

